// // This module increments the counter by 1 on every positive edge of the clock signal.
module down_counter(clk, rst, count);

    input  clk;
    input  rst;
    output reg [7:0] count;

    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 8'b11111111;
        else
            count <= count - 1;
    end

endmodule
